import dspy
import numpy as np
from collections import Counter

class BiasDriftDetector:
    def __init__(self):
        self.baseline_dists = {}

    def baseline(self, module, demo_slice, n=100):
        outputs = [module(**inputs).to_dict() for inputs in demo_slice[:n]]
        self.baseline_dists[str(demo_slice[0]['demographic'])] = Counter(outputs)

    def detect_drift(self, module, demo_slice, threshold=0.2):
        outputs = [module(**inputs).to_dict() for inputs in demo_slice]
        current_dist = Counter(outputs)
        baseline = self.baseline_dists[str(demo_slice[0]['demographic'])]

        drift_score = sum(abs(current_dist[k] - baseline.get(k, 0)) 
                         for k in set(current_dist) | set(baseline)) / len(outputs)
        return drift_score > threshold

# Usage
