import dspy
import re

PROTECTED_TERMS = {
    'gender': ['male', 'female', 'man', 'woman', 'boy', 'girl'],
    'race': ['black', 'white', 'asian', 'latino', 'hispanic'],
    'age': ['young', 'old', 'elderly', 'teen']
}

def scan_reasoning_chain(output, protected_attrs=['gender']):
    violations = []
    text = output.completions[0] if hasattr(output, 'completions') else str(output)

    for attr in protected_attrs:
        terms = PROTECTED_TERMS.get(attr, [])
        matches = [term for term in terms if re.search(rf'\b{term}\b', text, re.IGNORECASE)]
        if matches:
            violations.append({'attribute': attr, 'terms': matches})
    return violations

# Wrap DSPy module
class FairnessChain(dspy.Module):
    def __init__(self):
        self.reason = dspy.ChainOfThought('context -> answer')

    def forward(self, context):
        result = self.reason(context=context)
        violations = scan_reasoning_chain(result)
        if violations:
            print(f'BIAS ALERT: {violations}')
        return result

