import dspy

class CounterfactualFairness(dspy.Signature):
    '''Rate this resume for software engineering. Be fair and objective.'''
    resume: str = dspy.InputField()
    demographic: str = dspy.InputField(desc='Protected attribute for fairness check')
    rating: float = dspy.OutputField(desc='Score 1-10, same across demographics')

class FairnessAssert(dspy.Module):
    def __init__(self):
        self.rater = dspy.ChainOfThought(CounterfactualFairness)

    @dspy.assert_op(max_its=3, threshold=0.1)
    def fairness_check(self, resume_a_rating, resume_b_rating, demographic_a, demographic_b):
        '''Ensure equal ratings for identical qualifications different demographics'''
        return abs(resume_a_rating - resume_b_rating) < 0.5

    def forward(self, resume, demographic):
        rating = self.rater(resume=resume, demographic=demographic)

        # Counterfactual check
        counterfactual = self._create_counterfactual(resume, demographic)
        cf_rating = self.rater.resume(counterfactual, 'neutral')

        self.fairness_check(rating.rating, cf_rating.rating, demographic, 'neutral')

        return rating

    def _create_counterfactual(self, resume, demographic):
        # Neutralize demographic signals
        return re.sub(r'\b(Mr|Mrs|Ms|Miss)\.?\b', 'Alex', resume)

